CREATE PROCEDURE dbo.qrySimAbLeDa
    @IdDat datetime,
    @IdxNr int
AS
SELECT      ID2, ID0, ID3, ID4, RechNr, IDR, CONVERT(CHAR(10), Datum, 104) AS Datum, ID1 AS Typ, GONr AS Ziffer, IDKurz AS Bezeichnung, Kommentar, 
                        x AS Anz, Multi AS Faktor, Betrag, GesBetrag, WVBetrag, Steuer AS Steuersatz, Zeit, Währung, Gedruckt, Selekt, Kommentar2, Mandant, Einheit, IDP, 
                        IDM, IDD, Druckdatum, Lock
FROM          dbo.Tabelle_Abre
WHERE      (ID1 < 10) AND (ID0 = @IdxNr) AND (CONVERT(CHAR(10), Datum, 104) = @IdDat)
ORDER BY CONVERT(CHAR(8), Datum, 112), ID3, RechNr
GO


SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE dbo.qrySimAbDaG
    @IdSta datetime,
    @IdEnd datetime,
    @IdxNr int
AS
