FROM          dbo.Tabelle_Abre
WHERE      (Datum >= @IdSta) AND (Datum <= @IdEnd) AND (ID0 = @IdxNr) AND (Storniert = 0) AND (ID1 < 10)
GROUP BY Datum
GO


