CREATE PROCEDURE dbo.qrySimAdKr4c
    @IdJah int,
    @IdxNr int
AS
SELECT      TOP 100 PERCENT ID0, ID1, ID2, ID3, ID4, IDR, RechNr, Sorter, Datum, GONr, IDKurz, Kommentar, Kommentar2, x, Betrag, GesBetrag, WVBetrag, 
                        LaBetrag, Multi, Zeit, Punkt, PAD, Einheit, Steuer, Rabatt, Währung, Provision, Mandant, Druckdatum, IDP, IDM, IDD, OP, Gedruckt, Selekt, 
                        Analog
FROM          dbo.Tabelle_Abre
WHERE      (ID1 > 9) AND (ID1 <> 104) AND (ID1 <> 800) AND (Gedruckt = 0) AND (YEAR(Datum) = @IdJah) AND (ID0 = @IdxNr) AND (Storniert = 0)
GO


