CREATE PROCEDURE dbo.qryPrSimRe5
    @IdStr int
AS
SELECT      dbo.Tabelle_Abre.ID1 AS Typ, MIN(dbo.Tabelle_Abre.ID3) AS Sorter, dbo.Tabelle_Abre.GONr AS Ziffer, dbo.Tabelle_Abre.IDKurz AS Bezeichnung, 
                        MIN(dbo.Tabelle_Abre.Kommentar) AS Kommentar, MIN(dbo.Tabelle_Abre.Multi) AS Multi, dbo.Tabelle_Abre.Betrag AS Einzelbetrag, 
                        0 AS Gesamtbetrag, SUM(dbo.Tabelle_Abre.WVBetrag) AS Anzahlungsbetrag, SUM(dbo.Tabelle_Abre.Zeit) AS Zeit, COUNT(dbo.Tabelle_Abre.GONr) 
                        AS Anzahl, MIN(CONVERT(CHAR(10), dbo.Tabelle_Abre.Datum, 104)) AS Datum, dbo.Tabelle_AbreWr.Symbol AS Währung, 
                        MIN(dbo.Tabelle_AbreDia.GOID) AS ICD, MIN(dbo.Tabelle_AbreDia.IDKurz) AS Diagnose, MIN(dbo.Tabelle_Abre.Rabatt) AS Einzelrabatt, 
                        dbo.Tabelle_Abre.Analog AS Analog, MIN(dbo.Tabelle_Abre.RechNr) AS Taxe
FROM          dbo.Tabelle_AbreWr RIGHT OUTER JOIN
                        dbo.Tabelle_AbreRe ON dbo.Tabelle_AbreWr.IDW = dbo.Tabelle_AbreRe.Währung RIGHT OUTER JOIN
                        dbo.Tabelle_Abre ON dbo.Tabelle_AbreRe.ID1 = dbo.Tabelle_Abre.IDR LEFT OUTER JOIN
                        dbo.Tabelle_AbreDia ON dbo.Tabelle_Abre.IDD = dbo.Tabelle_AbreDia.ID2
WHERE      (dbo.Tabelle_Abre.IDR = @IdStr) AND (dbo.Tabelle_Abre.Storniert = 0)
GROUP BY dbo.Tabelle_Abre.ID1, dbo.Tabelle_Abre.GONr, dbo.Tabelle_Abre.IDKurz, dbo.Tabelle_Abre.Betrag, dbo.Tabelle_AbreWr.Symbol, 
                        dbo.Tabelle_Abre.Analog
HAVING       (dbo.Tabelle_Abre.ID1 < 10)
ORDER BY dbo.Tabelle_Abre.ID1, MIN(dbo.Tabelle_Abre.ID3), dbo.Tabelle_Abre.GONr
GO


