CREATE VIEW dbo.qryPrBuSt1a
AS
SELECT dbo.Tabelle_JourBuch.IDT, YEAR(dbo.Tabelle_JourBuch.Datum) AS Jahr, dbo.Tabelle_JourArt.IDA AS EA, 
                        MONTH(dbo.Tabelle_JourBuch.Datum) AS Monat, dbo.Tabelle_JourArt.IDKurz AS Typ, dbo.Tabelle_JourBuch.IDK AS Konto, dbo.Tabelle_JourBuch.IDG,
                         dbo.Tabelle_JourBuch.IDKurz AS Bezeichnung, SUM(dbo.Tabelle_JourBuch.Ausgabe) AS Ausgabe, SUM(dbo.Tabelle_JourBuch.Einnahme) 
                        AS Einnahme, dbo.Tabelle_JourBuch.Steuer AS Ausgabesteuer, dbo.Tabelle_JourBuch.Steuer AS Einnahmesteuer, dbo.Tabelle_AbreWr.Symbol
FROM          dbo.Tabelle_JourBuch INNER JOIN
                        dbo.Tabelle_AbreWr ON dbo.Tabelle_JourBuch.Währung = dbo.Tabelle_AbreWr.IDW INNER JOIN
                        dbo.Tabelle_JourArt ON dbo.Tabelle_JourBuch.IDA = dbo.Tabelle_JourArt.IDA
WHERE      (dbo.Tabelle_JourBuch.Ermittlung = 0) AND (dbo.Tabelle_JourBuch.Storniert = 0) AND (dbo.Tabelle_JourBuch.Serie = 0) AND 
                        (dbo.Tabelle_JourBuch.Vorlage = 0)
GROUP BY YEAR(dbo.Tabelle_JourBuch.Datum), dbo.Tabelle_JourArt.IDA, MONTH(dbo.Tabelle_JourBuch.Datum), dbo.Tabelle_JourArt.IDKurz, 
                        dbo.Tabelle_JourBuch.IDK, dbo.Tabelle_JourBuch.IDKurz, dbo.Tabelle_JourBuch.Steuer, dbo.Tabelle_AbreWr.Symbol, dbo.Tabelle_JourBuch.IDT, 
                        dbo.Tabelle_JourBuch.IDG
HAVING       (MONTH(dbo.Tabelle_JourBuch.Datum) IS NOT NULL) AND (dbo.Tabelle_JourBuch.IDT IS NOT NULL) AND (dbo.Tabelle_JourBuch.Steuer > 0)
GO


