                        dbo.Tabelle_JourArt.IDKurz AS Typ, dbo.Tabelle_JourBuch.IDK AS Konto, dbo.Tabelle_JourBuch.IDG, dbo.Tabelle_JourBuch.IDKurz AS Bezeichnung, 
                        SUM(dbo.Tabelle_JourBuch.Ausgabe) AS Ausgabe, SUM(dbo.Tabelle_JourBuch.Einnahme) AS Einnahme, 
                        dbo.Tabelle_JourBuch.Steuer AS Ausgabesteuer, dbo.Tabelle_JourBuch.Steuer AS Einnahmesteuer, dbo.Tabelle_AbreWr.Symbol
FROM          dbo.Tabelle_JourBuch INNER JOIN
