CREATE VIEW dbo.qryPrBuBa2a
AS
SELECT dbo.Tabelle_JourBuch.IDT, YEAR(dbo.Tabelle_JourBuch.Datum) AS Jahr, dbo.Tabelle_JourBuch.IDB, 
                        dbo.Tabelle_JourBank.IDKurz AS Gegenkonto, SUM(dbo.Tabelle_JourBuch.Ausgabe) AS Ausgaben, SUM(dbo.Tabelle_JourBuch.Einnahme) 
                        AS Einnahmen, dbo.Tabelle_AbreWr.Symbol
FROM          dbo.Tabelle_JourBuch INNER JOIN
                        dbo.Tabelle_JourBank ON dbo.Tabelle_JourBuch.IDB = dbo.Tabelle_JourBank.IDB LEFT OUTER JOIN
                        dbo.Tabelle_AbreWr ON dbo.Tabelle_JourBuch.Währung = dbo.Tabelle_AbreWr.IDW
WHERE      (dbo.Tabelle_JourBuch.Ermittlung = 0) AND (dbo.Tabelle_JourBuch.Storniert = 0) AND (dbo.Tabelle_JourBuch.Serie = 0) AND 
                        (dbo.Tabelle_JourBuch.Vorlage = 0)
GROUP BY YEAR(dbo.Tabelle_JourBuch.Datum), dbo.Tabelle_JourBuch.IDB, dbo.Tabelle_JourBank.IDKurz, dbo.Tabelle_AbreWr.Symbol, 
                        dbo.Tabelle_JourBuch.IDT
HAVING       (dbo.Tabelle_JourBuch.IDT IS NOT NULL) AND (YEAR(dbo.Tabelle_JourBuch.Datum) IS NOT NULL)
GO


