CREATE PROCEDURE dbo.qryPrLaBe2
    @IdStr nvarchar(250)
AS
SELECT     dbo.Tabelle_Lab_TestD.[Test-Ident] AS TestIdent, dbo.Tabelle_Lab_TestD.Testbezeichnung, dbo.Tabelle_Lab_TestD.Ergebniswert, 
                      dbo.Tabelle_Lab_TestD.Einheit, dbo.Tabelle_Lab_TestD.[Grenzwert-Indikator] AS Grenzwert, dbo.Tabelle_Lab_BerGru.IDKurz AS Status, 
                      dbo.Tabelle_Lab_Norm.[Normalwert-Text] AS Normalwert, dbo.Tabelle_Lab_HinTe.Hinweis, dbo.Tabelle_Lab_ErgTe.[Ergebnis-Text] AS Ergebnistext, 
                      dbo.Tabelle_Lab_TestD.Teststatus, dbo.Tabelle_Lab_TestD.Befundung, dbo.Tabelle_Lab_TestD.Abrechnungskennung, dbo.Tabelle_AbreKaO.IDTyp, 
                      dbo.Tabelle_AbreKaO.Sorter, dbo.Tabelle_AbreKaO.Selekt, dbo.Tabelle_AbreKaO.Favorit, dbo.Tabelle_AbreKaO.Automatic
FROM         dbo.Tabelle_Lab_Beri INNER JOIN
                      dbo.Tabelle_Lab_TestD ON dbo.Tabelle_Lab_Beri.ID0 = dbo.Tabelle_Lab_TestD.[Berichts-ID] INNER JOIN
                      dbo.Tabelle_AbreKaO ON dbo.Tabelle_Lab_TestD.[Test-Ident] = dbo.Tabelle_AbreKaO.GOIK INNER JOIN
                      dbo.Tabelle_Lab_BerGru ON dbo.Tabelle_AbreKaO.IDTyp = dbo.Tabelle_Lab_BerGru.ID2 LEFT OUTER JOIN
                      dbo.Tabelle_Lab_ErgTe ON dbo.Tabelle_Lab_TestD.ID0 = dbo.Tabelle_Lab_ErgTe.[Testdaten-ID] LEFT OUTER JOIN
                      dbo.Tabelle_Lab_HinTe ON dbo.Tabelle_Lab_TestD.ID0 = dbo.Tabelle_Lab_HinTe.[Testdaten-ID] LEFT OUTER JOIN
                      dbo.Tabelle_Lab_Norm ON dbo.Tabelle_Lab_TestD.ID0 = dbo.Tabelle_Lab_Norm.[Testdaten-ID]
WHERE     (dbo.Tabelle_Lab_TestD.Ergebniswert IS NOT NULL) AND (dbo.Tabelle_AbreKaO.ID3 = 2) AND (dbo.Tabelle_Lab_Beri.[Anforderungs-Ident] LIKE @IdStr)
ORDER BY dbo.Tabelle_AbreKaO.IDTyp, dbo.Tabelle_AbreKaO.Sorter
GO


SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER OFF
GO

CREATE PROCEDURE dbo.qryPrLaBe5
    @IdStr nvarchar(250)
AS
SELECT     dbo.Tabelle_Lab_TestD.[Test-Ident] AS TestIdent, dbo.Tabelle_Lab_TestD.Testbezeichnung, dbo.Tabelle_Lab_TestD.Ergebniswert, 
                      dbo.Tabelle_Lab_TestD.Einheit, dbo.Tabelle_Lab_TestD.[Grenzwert-Indikator] AS Grenzwert, 'Parameter' AS Status, 
                      dbo.Tabelle_Lab_Norm.[Normalwert-Text] AS Normalwert, dbo.Tabelle_Lab_HinTe.Hinweis, dbo.Tabelle_Lab_ErgTe.[Ergebnis-Text] AS Ergebnistext, 
                      dbo.Tabelle_Lab_TestD.Teststatus, dbo.Tabelle_Lab_TestD.Befundung, dbo.Tabelle_Lab_TestD.Abrechnungskennung
FROM         dbo.Tabelle_Lab_ErgTe RIGHT OUTER JOIN
                      dbo.Tabelle_Lab_Beri INNER JOIN
                      dbo.Tabelle_Lab_TestD ON dbo.Tabelle_Lab_Beri.ID0 = dbo.Tabelle_Lab_TestD.[Berichts-ID] ON 
                      dbo.Tabelle_Lab_ErgTe.[Testdaten-ID] = dbo.Tabelle_Lab_TestD.ID0 LEFT OUTER JOIN
                      dbo.Tabelle_Lab_HinTe ON dbo.Tabelle_Lab_TestD.ID0 = dbo.Tabelle_Lab_HinTe.[Testdaten-ID] LEFT OUTER JOIN
                      dbo.Tabelle_Lab_Norm ON dbo.Tabelle_Lab_TestD.ID0 = dbo.Tabelle_Lab_Norm.[Testdaten-ID]
WHERE     (dbo.Tabelle_Lab_TestD.Ergebniswert IS NOT NULL) AND (dbo.Tabelle_Lab_Beri.[Anforderungs-Ident] LIKE @IdStr)
GO


SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER OFF
GO

