CREATE VIEW dbo.qrySimAdDop
AS
SELECT MIN(ID0) AS ID0, MIN(ID3) AS ID3, IDKurz, MIN(Geboren) AS Geboren, MIN(Name) AS Name, MIN(Vorname) AS Vorname, 
                        MIN(Straße) AS Straße, MIN(PLZ) AS PLZ, MIN(Ort) AS Ort, MIN(Firma1) AS Firma1, MIN(Telefon1) AS Telefon1, MIN(Telefon2) AS Telefon2, 
                        MIN(Telefon3) AS Telefon3, MIN(Telefon4) AS Telefon4, MIN(Telefon5) AS Telefon5, MIN(Geschlecht) AS Geschlecht, MIN(Datum) AS Datum, 
                        MIN(Briefanrede) AS Briefanrede, MIN(Anschrift) AS Anschrift, MIN(TreKey) AS TreKey, MIN(Grafik) AS Grafik, MIN(GuiID) AS GuiID, MIN(Objekt) 
                        AS Objekt, MIN(IDP) AS IDP, MIN(Mandant) AS Mandant, VIP, MIN(Titel) AS Titel, MIN(Land) AS Land, MIN(Behindert) AS Behindert, Passiv, 
                        MIN(AdrGruppe) AS AdrGruppe, Versand
FROM          dbo.Tabelle_Patienten
GROUP BY IDKurz, VIP, Arzt, Passiv, Mitarbeiter, Versand
HAVING       (COUNT(IDKurz) > 1) AND (VIP = 0) AND (Mitarbeiter = 0) AND (Arzt = 0)
GO


