CREATE PROCEDURE dbo.qrySimAdKr7a
    @IdTyp int,
    @IdSta datetime,
    @IdEnd datetime
AS
SELECT      dbo.Tabelle_Patienten.ID0, dbo.Tabelle_Patienten.ID3, dbo.Tabelle_Patienten.IDKurz, dbo.Tabelle_Patienten.Geboren, dbo.Tabelle_Patienten.Name, 
                        dbo.Tabelle_Patienten.Vorname, dbo.Tabelle_Patienten.Straße, dbo.Tabelle_Patienten.PLZ, dbo.Tabelle_Patienten.Ort, dbo.Tabelle_Patienten.Firma1, 
                        dbo.Tabelle_Patienten.Telefon1, dbo.Tabelle_Patienten.Telefon2, dbo.Tabelle_Patienten.Telefon3, dbo.Tabelle_Patienten.Telefon4, 
                        dbo.Tabelle_Patienten.Telefon5, dbo.Tabelle_Patienten.Geschlecht, dbo.Tabelle_Patienten.Datum, dbo.Tabelle_Patienten.Briefanrede, 
                        dbo.Tabelle_Patienten.Anschrift, dbo.Tabelle_Patienten.TreKey, dbo.Tabelle_Patienten.Grafik, dbo.Tabelle_Patienten.GuiID, 
                        dbo.Tabelle_Patienten.Objekt, dbo.Tabelle_Patienten.IDP, dbo.Tabelle_Patienten.Mandant, dbo.Tabelle_Patienten.VIP, dbo.Tabelle_Patienten.Titel, 
                        dbo.Tabelle_Patienten.Land, dbo.Tabelle_Patienten.Behindert, dbo.Tabelle_Patienten.Passiv, dbo.Tabelle_Patienten.AdrGruppe, 
                        SUM(dbo.Tabelle_Abre.Betrag) AS Betrag, SUM(dbo.Tabelle_Abre.GesBetrag) AS GesBetrag, MAX(dbo.Tabelle_Abre.Datum) AS Sorter
FROM          dbo.Tabelle_Patienten INNER JOIN
                        dbo.Tabelle_Abre ON dbo.Tabelle_Patienten.ID0 = dbo.Tabelle_Abre.ID0
WHERE      (dbo.Tabelle_Abre.ID1 = @IdTyp) AND (dbo.Tabelle_Abre.Gedruckt = 0) AND (dbo.Tabelle_Abre.Datum >= @IdSta) AND 
                        (dbo.Tabelle_Abre.Datum <= @IdEnd)
GROUP BY dbo.Tabelle_Patienten.ID0, dbo.Tabelle_Patienten.ID3, dbo.Tabelle_Patienten.IDKurz, dbo.Tabelle_Patienten.Geboren, dbo.Tabelle_Patienten.Name, 
                        dbo.Tabelle_Patienten.Vorname, dbo.Tabelle_Patienten.Straße, dbo.Tabelle_Patienten.PLZ, dbo.Tabelle_Patienten.Ort, dbo.Tabelle_Patienten.Firma1, 
                        dbo.Tabelle_Patienten.Telefon1, dbo.Tabelle_Patienten.Telefon2, dbo.Tabelle_Patienten.Telefon3, dbo.Tabelle_Patienten.Telefon4, 
                        dbo.Tabelle_Patienten.Telefon5, dbo.Tabelle_Patienten.Geschlecht, dbo.Tabelle_Patienten.Datum, dbo.Tabelle_Patienten.Briefanrede, 
                        dbo.Tabelle_Patienten.Anschrift, dbo.Tabelle_Patienten.TreKey, dbo.Tabelle_Patienten.Grafik, dbo.Tabelle_Patienten.GuiID, 
                        dbo.Tabelle_Patienten.Objekt, dbo.Tabelle_Patienten.IDP, dbo.Tabelle_Patienten.Mandant, dbo.Tabelle_Patienten.Titel, dbo.Tabelle_Patienten.Land, 
                        dbo.Tabelle_Patienten.Behindert, dbo.Tabelle_Patienten.AdrGruppe, dbo.Tabelle_Patienten.VIP, dbo.Tabelle_Patienten.Passiv
ORDER BY MAX(dbo.Tabelle_Abre.Datum)
GO


