CREATE VIEW dbo.qryPrSimTag5
AS
SELECT dbo.Tabelle_AbreRe.IDP AS IDT, CAST(CONVERT(CHAR(10), dbo.Tabelle_Abre.Datum, 104) AS DATE) AS Datum, 
                        dbo.Tabelle_Patienten.IDKurz AS Patient, dbo.Tabelle_Abre.Steuer, dbo.Tabelle_Abre.ID1 AS Typ, COUNT(dbo.Tabelle_Abre.ID2) AS Anzahl, 
                        SUM(dbo.Tabelle_Abre.GesBetrag) AS Gesamt, SUM(dbo.Tabelle_Abre.Zeit) AS Zeit, dbo.Tabelle_Abre.IDM, Tabelle_Patienten_1.IDKurz AS Mandant, 
                        Tabelle_Patienten_2.IDKurz AS Mitarbeiter, CONVERT(CHAR(8), dbo.Tabelle_Abre.Datum, 112) AS Sorter
FROM          dbo.Tabelle_Patienten INNER JOIN
                        dbo.Tabelle_Abre ON dbo.Tabelle_Patienten.ID0 = dbo.Tabelle_Abre.ID0 INNER JOIN
                        dbo.Tabelle_AbreRe ON dbo.Tabelle_Abre.IDR = dbo.Tabelle_AbreRe.ID1 LEFT OUTER JOIN
                        dbo.Tabelle_Patienten Tabelle_Patienten_2 ON dbo.Tabelle_Abre.IDM = Tabelle_Patienten_2.ID0 LEFT OUTER JOIN
                        dbo.Tabelle_Patienten Tabelle_Patienten_1 ON dbo.Tabelle_AbreRe.IDP = Tabelle_Patienten_1.ID0
WHERE      (dbo.Tabelle_AbreRe.Storniert = 0) AND (dbo.Tabelle_AbreRe.Type LIKE N'R' OR
                        dbo.Tabelle_AbreRe.Type LIKE N'A' OR
                        dbo.Tabelle_AbreRe.Type LIKE N'L' OR
                        dbo.Tabelle_AbreRe.Type LIKE N'G' OR
                        dbo.Tabelle_AbreRe.Type LIKE N'I') AND (dbo.Tabelle_Abre.Storniert = 0)
GROUP BY CAST(CONVERT(CHAR(10), dbo.Tabelle_Abre.Datum, 104) AS DATE), dbo.Tabelle_Patienten.IDKurz, dbo.Tabelle_Abre.ID1, dbo.Tabelle_AbreRe.IDP, 
                        dbo.Tabelle_AbreRe.Type, Tabelle_Patienten_1.IDKurz, Tabelle_Patienten_2.IDKurz, dbo.Tabelle_Abre.Steuer, dbo.Tabelle_Abre.IDM, 
                        CONVERT(CHAR(8), dbo.Tabelle_Abre.Datum, 112)
HAVING       (dbo.Tabelle_Abre.ID1 < 10)
GO


