CREATE PROCEDURE dbo.qryPrSimRe2b
    @IdStr int
AS
SELECT      dbo.Tabelle_Abre.ID0 AS PatNr, CONVERT(CHAR(10), dbo.Tabelle_Abre.Datum, 104) AS Behandlungsdatum, CONVERT(CHAR(8), 
                        dbo.Tabelle_Abre.Datum, 112) AS Sortierung, CAST(dbo.Tabelle_Abre.ID1 AS CHAR(1)) + CONVERT(CHAR(8), dbo.Tabelle_Abre.Datum, 112) 
                        AS Gruppierung, dbo.Tabelle_Abre.Steuer AS Steuersatz, dbo.Tabelle_Abre.RechNr AS Taxe, dbo.Tabelle_Abre.ID3 AS Position, 
                        dbo.Tabelle_Abre.ID1 AS Typ, dbo.Tabelle_Abre.GONr AS Ziffer, dbo.Tabelle_Abre.IDKurz AS Bezeichnung, dbo.Tabelle_Abre.Kommentar, 
                        dbo.Tabelle_Abre.Betrag AS Einzelbetrag, dbo.Tabelle_Abre.GesBetrag AS Gesamtbetrag, dbo.Tabelle_Abre.WVBetrag AS Anzahlungsbetrag, 
                        dbo.Tabelle_Abre.LaBetrag AS Einstandspreis, dbo.Tabelle_Abre.x AS Anzahl, dbo.Tabelle_Abre.Multi, dbo.Tabelle_Abre.Einheit, 
                        dbo.Tabelle_Abre.Rabatt AS Einzelrabatt, dbo.Tabelle_Abre.Punkt, dbo.Tabelle_Abre.Provision, dbo.Tabelle_Abre.IDR AS ReNr, dbo.Tabelle_Abre.Zeit, 
                        dbo.Tabelle_AbreWr.Symbol AS Währung, dbo.Tabelle_AbreDia.GOID AS ICD, dbo.Tabelle_AbreDia.IDKurz AS Diagnose, 
                        dbo.Tabelle_Abre.Druckdatum, dbo.Tabelle_Abre.Analog, dbo.Tabelle_Abre.IDM, dbo.Tabelle_Patienten.IDKurz AS Mitarbeiter
FROM          dbo.Tabelle_AbreTyp RIGHT OUTER JOIN
                        dbo.Tabelle_Abre ON dbo.Tabelle_AbreTyp.IDT = dbo.Tabelle_Abre.ID1 LEFT OUTER JOIN
                        dbo.Tabelle_AbreWr RIGHT OUTER JOIN
                        dbo.Tabelle_AbreRe ON dbo.Tabelle_AbreWr.IDW = dbo.Tabelle_AbreRe.Währung ON 
                        dbo.Tabelle_Abre.IDR = dbo.Tabelle_AbreRe.ID1 LEFT OUTER JOIN
                        dbo.Tabelle_Patienten ON dbo.Tabelle_Abre.IDM = dbo.Tabelle_Patienten.ID0 LEFT OUTER JOIN
                        dbo.Tabelle_AbreDia ON dbo.Tabelle_Abre.IDD = dbo.Tabelle_AbreDia.ID2
WHERE      (dbo.Tabelle_Abre.ID1 < 10) AND (dbo.Tabelle_Abre.IDR = @IdStr) AND (dbo.Tabelle_Abre.Storniert = 0)
ORDER BY CONVERT(CHAR(8), dbo.Tabelle_Abre.Datum, 112), CAST(dbo.Tabelle_Abre.ID1 AS CHAR(1)) + CONVERT(CHAR(8), dbo.Tabelle_Abre.Datum, 112), 
                        dbo.Tabelle_Abre.Steuer, dbo.Tabelle_Abre.ID3
