CREATE PROCEDURE dbo.qrySimAdKr4f
    @IdJah int,
    @IdMit int
AS
SELECT      TOP 100 PERCENT dbo.Tabelle_Patienten.ID0, dbo.Tabelle_Patienten.ID3, dbo.Tabelle_Patienten.IDKurz, dbo.Tabelle_Patienten.Geboren, 
                        dbo.Tabelle_Patienten.Name, dbo.Tabelle_Patienten.Vorname, dbo.Tabelle_Patienten.Straße, dbo.Tabelle_Patienten.PLZ, dbo.Tabelle_Patienten.Ort, 
                        dbo.Tabelle_Patienten.Firma1, dbo.Tabelle_Patienten.Telefon1, dbo.Tabelle_Patienten.Telefon2, dbo.Tabelle_Patienten.Telefon3, 
                        dbo.Tabelle_Patienten.Telefon4, dbo.Tabelle_Patienten.Telefon5, dbo.Tabelle_Patienten.Geschlecht, dbo.Tabelle_Patienten.Datum, 
                        dbo.Tabelle_Patienten.Briefanrede, dbo.Tabelle_Patienten.Anschrift, dbo.Tabelle_Patienten.TreKey, dbo.Tabelle_Patienten.Grafik, 
                        dbo.Tabelle_Patienten.GuiID, dbo.Tabelle_Patienten.Objekt, dbo.Tabelle_Patienten.IDP, dbo.Tabelle_Patienten.Mandant, dbo.Tabelle_Patienten.VIP, 
                        dbo.Tabelle_Patienten.Titel, dbo.Tabelle_Patienten.Land, dbo.Tabelle_Patienten.Behindert, dbo.Tabelle_Patienten.Passiv, 
                        dbo.Tabelle_Patienten.AdrGruppe, dbo.Tabelle_Patienten.Mailing, SUM(dbo.Tabelle_Abre.Betrag) AS Betrag, SUM(dbo.Tabelle_Abre.GesBetrag) 
                        AS GesBetrag, MAX(dbo.Tabelle_Abre.Datum) AS Sorter
FROM          dbo.Tabelle_Patienten INNER JOIN
                        dbo.Tabelle_Abre ON dbo.Tabelle_Patienten.ID0 = dbo.Tabelle_Abre.ID0
WHERE      (dbo.Tabelle_Patienten.Arzt = 0) AND (dbo.Tabelle_Patienten.Mitarbeiter = 0) AND (dbo.Tabelle_Abre.ID1 > 9) AND (dbo.Tabelle_Abre.ID1 <> 104) AND 
                        (dbo.Tabelle_Abre.ID1 <> 800) AND (YEAR(dbo.Tabelle_Abre.Datum) = @IdJah) AND (dbo.Tabelle_Abre.Gedruckt = 1) AND 
                        (dbo.Tabelle_Abre.IDM = @IdMit)
GROUP BY dbo.Tabelle_Patienten.ID0, dbo.Tabelle_Patienten.ID3, dbo.Tabelle_Patienten.IDKurz, dbo.Tabelle_Patienten.Geboren, dbo.Tabelle_Patienten.Name, 
                        dbo.Tabelle_Patienten.Vorname, dbo.Tabelle_Patienten.Straße, dbo.Tabelle_Patienten.PLZ, dbo.Tabelle_Patienten.Ort, dbo.Tabelle_Patienten.Firma1, 
                        dbo.Tabelle_Patienten.Telefon1, dbo.Tabelle_Patienten.Telefon2, dbo.Tabelle_Patienten.Telefon3, dbo.Tabelle_Patienten.Telefon4, 
                        dbo.Tabelle_Patienten.Telefon5, dbo.Tabelle_Patienten.Geschlecht, dbo.Tabelle_Patienten.Datum, dbo.Tabelle_Patienten.Briefanrede, 
                        dbo.Tabelle_Patienten.Anschrift, dbo.Tabelle_Patienten.TreKey, dbo.Tabelle_Patienten.Grafik, dbo.Tabelle_Patienten.GuiID, 
                        dbo.Tabelle_Patienten.Objekt, dbo.Tabelle_Patienten.IDP, dbo.Tabelle_Patienten.Mandant, dbo.Tabelle_Patienten.Titel, dbo.Tabelle_Patienten.Land, 
                        dbo.Tabelle_Patienten.Behindert, dbo.Tabelle_Patienten.AdrGruppe, dbo.Tabelle_Patienten.Mailing, dbo.Tabelle_Patienten.Passiv, 
                        dbo.Tabelle_Patienten.VIP
HAVING       (dbo.Tabelle_Patienten.VIP = 0)
ORDER BY MAX(dbo.Tabelle_Abre.Datum)
GO


