CREATE PROCEDURE dbo.qrySimBuWek04
    @IdWek int,
    @IdJah int,
    @IdBnk int
AS
SELECT      dbo.Tabelle_JourBuch.ID0, dbo.Tabelle_JourBuch.Datum, dbo.Tabelle_JourBuch.Buchtext, dbo.Tabelle_JourBuch.Einnahme, 
                        dbo.Tabelle_JourBuch.Ausgabe, dbo.Tabelle_AbreWr.Symbol AS W, dbo.Tabelle_JourBuch.IDK AS Konto, dbo.Tabelle_JourBuch.IDG, 
                        dbo.Tabelle_JourBank.IDKurz AS Gegenkonto, dbo.Tabelle_JourBuch.RechNr, dbo.Tabelle_JourBuch.IDR, dbo.Tabelle_JourBuch.Beleg, 
                        dbo.Tabelle_JourBuch.IDKurz AS Kontenbezeichnung, dbo.Tabelle_JourArt.IDKurz AS Buchungsart, dbo.Tabelle_JourBuch.Steuer, 
                        dbo.Tabelle_JourBuch.Privat, dbo.Tabelle_JourBuch.Abziehbar, dbo.Tabelle_JourBuch.IDB, dbo.Tabelle_JourBuch.IDA, 
                        dbo.Tabelle_JourBuch.Währung, dbo.Tabelle_JourBuch.Ermittlung, dbo.Tabelle_JourBuch.IDP, dbo.Tabelle_JourBuch.IDA AS IDArt, 
                        dbo.Tabelle_JourBuch.IDB AS IDBank, dbo.Tabelle_JourBuch.Kommentar, dbo.Tabelle_JourBuch.IDT, dbo.Tabelle_JourBuch.Berichtdatum, 
                        dbo.Tabelle_JourBuch.GuiID, dbo.Tabelle_JourBuch.Storniert, dbo.Tabelle_JourBuch.IDM, dbo.Tabelle_JourBuch.Lock, 
                        dbo.Tabelle_Patienten.IDKurz AS Patient, dbo.Tabelle_JourBuch.Datei, dbo.Tabelle_JourBuch.Doppelt, dbo.Tabelle_JourBuch.Zuordnung, 
                        dbo.Tabelle_JourBuch.TSELog, dbo.Tabelle_JourBuch.TSEZahl, dbo.Tabelle_JourBuch.TSESign
FROM          dbo.Tabelle_Patienten RIGHT OUTER JOIN
                        dbo.Tabelle_JourBuch ON dbo.Tabelle_Patienten.ID0 = dbo.Tabelle_JourBuch.ID0 LEFT OUTER JOIN
                        dbo.Tabelle_AbreWr ON dbo.Tabelle_JourBuch.Währung = dbo.Tabelle_AbreWr.IDW LEFT OUTER JOIN
                        dbo.Tabelle_JourArt ON dbo.Tabelle_JourBuch.IDA = dbo.Tabelle_JourArt.IDA LEFT OUTER JOIN
                        dbo.Tabelle_JourBank ON dbo.Tabelle_JourBuch.IDB = dbo.Tabelle_JourBank.IDB
WHERE      (dbo.Tabelle_JourBuch.Anfang = 0) AND (DATEPART(wk, dbo.Tabelle_JourBuch.Datum) = @IdWek) AND (YEAR(dbo.Tabelle_JourBuch.Datum) 
                        = @IdJah) AND (dbo.Tabelle_JourBuch.IDB = @IdBnk) AND (dbo.Tabelle_JourBuch.Serie = 0) AND (dbo.Tabelle_JourBuch.Vorlage = 0)
ORDER BY dbo.Tabelle_JourBuch.Datum, dbo.Tabelle_JourBuch.Beleg DESC
GO


SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON
GO


CREATE VIEW dbo.qryPrBuJo3
AS
SELECT      TOP 1 dbo.Tabelle_JourBuch.Datum, dbo.Tabelle_JourBuch.IDK AS Konto, dbo.Tabelle_JourBuch.IDG, dbo.Tabelle_JourBank.IDKurz AS Gegenkonto, 
                        dbo.Tabelle_JourBuch.ID0 AS Nr, dbo.Tabelle_JourBuch.IDKurz AS Kontenbezeichnung, dbo.Tabelle_JourBuch.Einnahme, 
                        dbo.Tabelle_JourBuch.Ausgabe, dbo.Tabelle_AbreWr.IDW AS W, dbo.Tabelle_JourBuch.RechNr, dbo.Tabelle_JourBuch.IDR, 
                        dbo.Tabelle_JourBuch.Beleg, 
                        CASE WHEN dbo.Tabelle_JourBuch.IDP > 0 THEN dbo.Tabelle_JourBuch.Buchtext + N' ' + dbo.Tabelle_Patienten.IDKurz WHEN dbo.Tabelle_JourBuch.IDP
                         = 0 OR
                        dbo.Tabelle_JourBuch.IDP IS NULL THEN dbo.Tabelle_JourBuch.Buchtext END AS Buchtext, dbo.Tabelle_JourArt.IDKurz AS Buchungsart, 
                        dbo.Tabelle_JourBuch.Steuer, dbo.Tabelle_JourBuch.Privat, dbo.Tabelle_JourBuch.Abziehbar, dbo.Tabelle_JourBuch.Ermittlung, 
                        dbo.Tabelle_JourBuch.IDP AS PatNr, dbo.Tabelle_JourBuch.Kommentar, dbo.Tabelle_JourBuch.IDT, dbo.Tabelle_JourBuch.Berichtdatum, 
                        dbo.Tabelle_JourBuch.IDB, dbo.Tabelle_AbreWr.Symbol, 0 AS Saldo, MONTH(dbo.Tabelle_JourBuch.Datum) AS Monat, DATEPART(wk, 
                        dbo.Tabelle_JourBuch.Datum) AS Woche, dbo.Tabelle_JourBuch.Datei
FROM          dbo.Tabelle_JourBuch LEFT OUTER JOIN
                        dbo.Tabelle_Patienten ON dbo.Tabelle_JourBuch.IDP = dbo.Tabelle_Patienten.ID0 LEFT OUTER JOIN
                        dbo.Tabelle_AbreWr ON dbo.Tabelle_JourBuch.Währung = dbo.Tabelle_AbreWr.IDW LEFT OUTER JOIN
                        dbo.Tabelle_JourBank ON dbo.Tabelle_JourBuch.IDB = dbo.Tabelle_JourBank.IDB LEFT OUTER JOIN
                        dbo.Tabelle_JourArt ON dbo.Tabelle_JourBuch.IDA = dbo.Tabelle_JourArt.IDA
WHERE      (dbo.Tabelle_JourBuch.Anfang = 0) AND (dbo.Tabelle_JourBuch.Datum IS NOT NULL) AND (dbo.Tabelle_JourBuch.Serie = 0) AND 
                        (dbo.Tabelle_JourBuch.Vorlage = 0) AND (dbo.Tabelle_JourBuch.Storniert = 0)
ORDER BY dbo.Tabelle_JourBuch.Datum DESC, dbo.Tabelle_JourBank.Konto, Gegenkonto
GO


SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON
GO

