CREATE PROCEDURE dbo.qryLabBeThe
    @IdxNr int
AS
SELECT      dbo.Tabelle_Lab_Beri.ID0, dbo.Tabelle_Lab_Beri.[Anforderungs-Ident] AS Auftrag, dbo.Tabelle_Lab_Beri.Fertig AS F, 
                        dbo.Tabelle_Patienten.IDKurz AS Kunde, dbo.Tabelle_Lab_Beri.Befundart, dbo.Tabelle_Lab_Beri.[Familienname Patient] AS Name, 
                        dbo.Tabelle_Lab_Beri.[Vorname Patient] AS Vorname, dbo.Tabelle_Lab_Beri.[Geburtsdatum Patient] AS Geboren, dbo.Tabelle_Lab_Beri.Befund AS B, 
                        dbo.Tabelle_Patienten.Bank AS Report, dbo.Tabelle_Lab_Beri.[Auftragsnummer Labor] AS Labor, 
                        dbo.Tabelle_Lab_Beri.[Auftragseingang Labor] AS [L-Eingang], dbo.Tabelle_Lab_Beri.Berichtsdatum AS [L-Ausgang], 
                        dbo.Tabelle_Lab_Beri.[Zugeteilte Arztnummer] AS Arztnummer, dbo.Tabelle_Lab_Beri.[Geschlecht Patient] AS Geschlecht, 
                        dbo.Tabelle_Lab_SaArt.Beschreibung, dbo.Tabelle_Lab_Beri.Berichtsart, dbo.Tabelle_Lab_Beri.IDP, dbo.Tabelle_Lab_Beri.Befundung, 
                        dbo.Tabelle_Lab_Beri.Selekt, dbo.Tabelle_Lab_Beri.Importdatei, dbo.Tabelle_Patienten.Telefon5, dbo.Tabelle_Patienten.Telefon3 AS Telefax, 
                        dbo.Tabelle_Patienten.Briefanrede, dbo.Tabelle_Lab_Beri.[Anforderungs-Ident] AS IDA, dbo.Tabelle_Lab_Beri.Bemerkung AS Kommentar, 
                        dbo.Tabelle_Lab_Beri.IP0, dbo.Tabelle_Lab_Beri.Kostenträgeruntergruppe, dbo.Tabelle_Lab_Beri.ID3
FROM          dbo.Tabelle_Lab_SaArt INNER JOIN
                        dbo.Tabelle_Lab_Beri ON dbo.Tabelle_Lab_SaArt.Satzart = dbo.Tabelle_Lab_Beri.Berichtsart LEFT OUTER JOIN
