                      dbo.Tabelle_Lab_Beri.[OstWest-Status VK] AS OstWest, dbo.Tabelle_Lab_Beri.Gebührenordnung, dbo.Tabelle_Lab_Beri.Abrechnungsart, 
                      dbo.Tabelle_Lab_Beri.Privattarif, dbo.Tabelle_Lab_Beri.Abrechnungsgebiet, dbo.Tabelle_Lab_Beri.[Letzter Einlesetag VK Quartal] AS Einlesetag, 
