SELECT      TOP 3 dbo.Tabelle_AbreRe.PLZ, dbo.Tabelle_AbreRe.RechNr, dbo.Tabelle_AbreRe.IDR, dbo.Tabelle_AbreRe.ID1, dbo.Tabelle_Patienten.IDKurz, 
