FROM          dbo.Tabelle_AbreRe LEFT OUTER JOIN
                        dbo.Tabelle_Patienten ON dbo.Tabelle_AbreRe.ID0 = dbo.Tabelle_Patienten.ID0
WHERE      (dbo.Tabelle_AbreRe.IDP = @IdxNr) AND (YEAR(dbo.Tabelle_AbreRe.Datum) = @IdJah) AND (dbo.Tabelle_AbreRe.Type LIKE @IdStr)
