CREATE PROCEDURE dbo.qrySimOPMan2
    @IdxNr int
AS
SELECT      dbo.Tabelle_AbreOP.ID1, dbo.Tabelle_AbreOP.RechNr, dbo.Tabelle_Patienten.IDKurz AS Patient, dbo.Tabelle_AbreOP.Datum, 
                        dbo.Tabelle_AbreOP.Fällig, dbo.Tabelle_AbreOP.IDM AS Stufe, dbo.Tabelle_AbreOP.Betrag, dbo.Tabelle_AbreOP.Offen, dbo.Tabelle_AbreOP.Bezahlt, 
                        dbo.Tabelle_AbreOP.Einzahlung, dbo.Tabelle_AbreOP.Mahnfrist, dbo.Tabelle_AbreWr.Symbol AS W, dbo.Tabelle_AbreWr.IDW, 
                        dbo.Tabelle_AbreOP.Mahnbar, dbo.Tabelle_AbreOP.Intervall, dbo.Tabelle_AbreOP.ID0, dbo.Tabelle_AbreOP.Währung, dbo.Tabelle_AbreOP.IDR, 
                        dbo.Tabelle_AbreOP.Beleg, dbo.Tabelle_AbreOP.Selekt, dbo.Tabelle_AbreOP.IDP, dbo.Tabelle_AbreOP.Kommentar, 
                        dbo.Tabelle_AbreOP.Berichtdatum, dbo.Tabelle_AbreOP.Steuer, dbo.Tabelle_AbreOP.Mahnung1, dbo.Tabelle_AbreOP.Mahnung2, 
                        dbo.Tabelle_AbreOP.Mahnung3, dbo.Tabelle_AbreOP.Mahnung4, dbo.Tabelle_AbreOP.Mahnung5, dbo.Tabelle_AbreOP.Konto, 
                        dbo.Tabelle_AbreOP.BLZ, dbo.Tabelle_AbreOP.IDT, dbo.Tabelle_AbreOP.IBAN, dbo.Tabelle_AbreOP.BIC, dbo.Tabelle_AbreOP.GuiID, 
                        dbo.Tabelle_AbreOP.Gebuehr, dbo.Tabelle_AbreOP.Versand
FROM          dbo.Tabelle_AbreWr RIGHT OUTER JOIN
                        dbo.Tabelle_AbreOP ON dbo.Tabelle_AbreWr.IDW = dbo.Tabelle_AbreOP.Währung LEFT OUTER JOIN
                        dbo.Tabelle_Patienten ON dbo.Tabelle_AbreOP.ID0 = dbo.Tabelle_Patienten.ID0
WHERE      (dbo.Tabelle_AbreOP.IDP = @IdxNr) AND (dbo.Tabelle_AbreOP.Selekt = 0)
