                        dbo.Tabelle_JourBank.IDKurz AS Gegenkonto, dbo.Tabelle_JourBuch.RechNr, dbo.Tabelle_JourBuch.IDR, dbo.Tabelle_JourBuch.Beleg, 
                        dbo.Tabelle_JourBuch.IDKurz AS Kontenbezeichnung, dbo.Tabelle_JourBuch.IDGegen, dbo.Tabelle_JourArt.IDKurz AS Buchungsart, 
                        dbo.Tabelle_JourBuch.Steuer, dbo.Tabelle_JourBuch.Privat, dbo.Tabelle_JourBuch.Abziehbar, dbo.Tabelle_JourBuch.IDB, dbo.Tabelle_JourBuch.IDA, 
                        dbo.Tabelle_JourBuch.Währung, dbo.Tabelle_JourBuch.Ermittlung, dbo.Tabelle_JourBuch.IDP, dbo.Tabelle_JourBuch.IDA AS IDArt, 
                        dbo.Tabelle_JourBuch.IDB AS IDBank, dbo.Tabelle_JourBuch.Kommentar, dbo.Tabelle_JourBuch.IDT, dbo.Tabelle_JourBuch.Berichtdatum, 
                        dbo.Tabelle_JourBuch.GuiID, dbo.Tabelle_JourBuch.Storniert, dbo.Tabelle_JourBuch.IDM, dbo.Tabelle_JourBuch.Lock, 
                        dbo.Tabelle_Patienten.IDKurz AS Patient, dbo.Tabelle_JourBuch.Datei, dbo.Tabelle_JourBuch.Doppelt, dbo.Tabelle_JourBuch.Zuordnung, 
                        dbo.Tabelle_JourBuch.TSELog, dbo.Tabelle_JourBuch.TSEZahl, dbo.Tabelle_JourBuch.TSESign
FROM          dbo.Tabelle_Patienten RIGHT OUTER JOIN
                        dbo.Tabelle_JourBuch ON dbo.Tabelle_Patienten.ID0 = dbo.Tabelle_JourBuch.IDP LEFT OUTER JOIN
                        dbo.Tabelle_AbreWr ON dbo.Tabelle_JourBuch.Währung = dbo.Tabelle_AbreWr.IDW LEFT OUTER JOIN
