CREATE VIEW dbo.qryPrLaUm2
AS
SELECT Tabelle_Patienten_1.IDKurz AS Auftraggeber, Tabelle_Patienten_1.ID0 AS Kundennummer, Tabelle_Patienten_1.Briefanrede, 
                      Tabelle_Patienten_1.Bank, Tabelle_Patienten_1.Konto, Tabelle_Patienten_1.BLZ, Tabelle_Patienten_1.Anschrift, dbo.Tabelle_AbreRe.ID1 AS ReNr, 
                      dbo.Tabelle_AbreRe.ID0 AS PatNr, dbo.Tabelle_AbreRe.RechNr AS Rechnungsnummer, dbo.Tabelle_AbreRe.IDKurz AS Patient, 
                      dbo.Tabelle_AbreRe.Datum, dbo.Tabelle_AbreRe.Fallig AS Fällig, dbo.Tabelle_AbreRe.GesBetrag AS Rechbetrag, 
                      dbo.Tabelle_AbreRe.WVBetrag AS Laborpreis, dbo.Tabelle_AbreRe.GesBetrag * 0.08 AS Provision, 
                      dbo.Tabelle_AbreRe.GesBetrag - dbo.Tabelle_AbreRe.GesBetrag * 0.08 AS Abrechnung, dbo.Tabelle_AbreRe.Anzahlung, dbo.Tabelle_AbreRe.Ziel, 
                      dbo.Tabelle_AbreWr.Symbol
