                      dbo.Tabelle_Patienten INNER JOIN
                      dbo.Tabelle_Patienten Tabelle_Patienten_1 ON dbo.Tabelle_Patienten.IDP = Tabelle_Patienten_1.ID0 ON 
                      dbo.Tabelle_AbreRe.ID0 = dbo.Tabelle_Patienten.ID0
