                        @Telefon3, @Telefon4, @Telefon5, @Telefon6, @Geboren, @Datum, @LastModification, @Internet, @Bemerkung, @R_Anrede, @Vorname, @Name, 
                        @R_Firma1, @R_Straße, @R_Ort, @R_PLZ, @R_Land, @Beruf, @Anrede, @Geschlecht, @Kopien, @Währung, @Versicherungsart, @Passiv, 0)
