CREATE PROCEDURE dbo.qryDAVAdCh6
    @IDKurz nvarchar(150),
    @Firma nvarchar(100),
    @Anrede nvarchar(50),
    @Titel nvarchar(50),
    @Name nvarchar(150),
    @Vorname nvarchar(150),
