CREATE VIEW dbo.qryPrBuJo4
AS
SELECT dbo.Tabelle_JourBank.IDKurz AS Gegenkonto, dbo.Tabelle_JourBuch.IDK AS Konto, dbo.Tabelle_JourBuch.IDG, 
                        dbo.Tabelle_JourBuch.Datum, dbo.Tabelle_JourBuch.ID0 AS Nr, dbo.Tabelle_JourBuch.IDKurz AS Kontenbezeichnung, 
                        dbo.Tabelle_JourBuch.Einnahme, dbo.Tabelle_JourBuch.Ausgabe, dbo.Tabelle_AbreWr.IDW AS W, dbo.Tabelle_JourBuch.RechNr, 
                        dbo.Tabelle_JourBuch.IDR, dbo.Tabelle_JourBuch.Beleg, 
                        CASE WHEN dbo.Tabelle_JourBuch.IDP > 0 THEN dbo.Tabelle_JourBuch.Buchtext + N' ' + dbo.Tabelle_Patienten.IDKurz WHEN dbo.Tabelle_JourBuch.IDP
                         = 0 OR
                        dbo.Tabelle_JourBuch.IDP IS NULL THEN dbo.Tabelle_JourBuch.Buchtext END AS Buchtext, dbo.Tabelle_JourArt.IDKurz AS Buchungsart, 
                        dbo.Tabelle_JourBuch.Steuer, dbo.Tabelle_JourBuch.Privat, dbo.Tabelle_JourBuch.Abziehbar, dbo.Tabelle_JourBuch.Ermittlung, 
                        dbo.Tabelle_JourBuch.IDP AS PatNr, dbo.Tabelle_JourBuch.Kommentar, dbo.Tabelle_JourBuch.IDT, dbo.Tabelle_JourBuch.Berichtdatum, 
                        dbo.Tabelle_JourBuch.IDB, dbo.Tabelle_AbreWr.Symbol, 0 AS Saldo, MONTH(dbo.Tabelle_JourBuch.Datum) AS Monat, DATEPART(wk, 
                        dbo.Tabelle_JourBuch.Datum) AS Woche, dbo.Tabelle_JourBuch.Datei
FROM          dbo.Tabelle_JourBuch LEFT OUTER JOIN
                        dbo.Tabelle_Patienten ON dbo.Tabelle_JourBuch.IDP = dbo.Tabelle_Patienten.ID0 LEFT OUTER JOIN
                        dbo.Tabelle_AbreWr ON dbo.Tabelle_JourBuch.Währung = dbo.Tabelle_AbreWr.IDW LEFT OUTER JOIN
                        dbo.Tabelle_JourBank ON dbo.Tabelle_JourBuch.IDB = dbo.Tabelle_JourBank.IDB LEFT OUTER JOIN
                        dbo.Tabelle_JourArt ON dbo.Tabelle_JourBuch.IDA = dbo.Tabelle_JourArt.IDA
WHERE      (dbo.Tabelle_JourBuch.Anfang = 0) AND (dbo.Tabelle_JourBuch.Datum IS NOT NULL) AND (dbo.Tabelle_JourBuch.Serie = 0) AND 
                        (dbo.Tabelle_JourBuch.Vorlage = 0) AND (dbo.Tabelle_JourBuch.Storniert = 0)
GO


