CREATE PROCEDURE dbo.qryPrSimRe6
    @IdStr int,
    @IdDat datetime
AS
SELECT      dbo.Tabelle_Abre.GONr AS Ziffer, dbo.Tabelle_Abre.x AS Anzahl, dbo.Tabelle_Abre.Multi, dbo.Tabelle_Abre.Betrag AS Einzelbetrag, 
                        dbo.Tabelle_Abre.GesBetrag AS Gesamtbetrag, dbo.Tabelle_Abre.IDR, dbo.Tabelle_Abre.WVBetrag AS Anzahlungsbetrag, 
                        dbo.Tabelle_Abre.Steuer AS Steuersatz, dbo.Tabelle_AbreWr.Symbol AS Währung, dbo.Tabelle_Abre.Zeit, dbo.Tabelle_AbreDia.GOID AS ICD, 
                        dbo.Tabelle_AbreDia.IDKurz AS Diagnose, dbo.Tabelle_Abre.Analog, dbo.Tabelle_Abre.IDM, dbo.Tabelle_Patienten.IDKurz AS Mitarbeiter, 
                        dbo.Tabelle_Abre.RechNr AS Taxe
FROM          dbo.Tabelle_AbreWr RIGHT OUTER JOIN
                        dbo.Tabelle_AbreRe ON dbo.Tabelle_AbreWr.IDW = dbo.Tabelle_AbreRe.Währung RIGHT OUTER JOIN
                        dbo.Tabelle_Abre ON dbo.Tabelle_AbreRe.ID1 = dbo.Tabelle_Abre.IDR LEFT OUTER JOIN
                        dbo.Tabelle_Patienten ON dbo.Tabelle_Abre.IDM = dbo.Tabelle_Patienten.ID0 LEFT OUTER JOIN
                        dbo.Tabelle_AbreDia ON dbo.Tabelle_Abre.IDD = dbo.Tabelle_AbreDia.ID2
WHERE      (dbo.Tabelle_Abre.IDR = @IdStr) AND (dbo.Tabelle_Abre.ID1 < 10) AND (dbo.Tabelle_Abre.ID1 <> 6) AND (CONVERT(VARCHAR, 
                        dbo.Tabelle_Abre.Datum, 104) = @IdDat) AND (dbo.Tabelle_Abre.Storniert = 0)
ORDER BY CONVERT(VARCHAR, dbo.Tabelle_Abre.Datum, 112), dbo.Tabelle_Abre.ID3
GO


