CREATE PROCEDURE dbo.qrySimAdKr7b
    @IdTyp int,
    @IdSta datetime,
    @IdEnd datetime
AS
SELECT      dbo.Tabelle_Patienten.ID0, dbo.Tabelle_Patienten.ID3, dbo.Tabelle_Patienten.IDKurz, dbo.Tabelle_Patienten.Geboren, dbo.Tabelle_Patienten.Name, 
                        dbo.Tabelle_Patienten.Vorname, dbo.Tabelle_Patienten.Straße, dbo.Tabelle_Patienten.PLZ, dbo.Tabelle_Patienten.Ort, dbo.Tabelle_Patienten.Firma1, 
                        dbo.Tabelle_Patienten.Telefon1, dbo.Tabelle_Patienten.Telefon2, dbo.Tabelle_Patienten.Telefon3, dbo.Tabelle_Patienten.Telefon4, 
                        dbo.Tabelle_Patienten.Telefon5, dbo.Tabelle_Patienten.Geschlecht, dbo.Tabelle_Patienten.Datum, dbo.Tabelle_Patienten.Briefanrede, 
                        dbo.Tabelle_Patienten.Anschrift, dbo.Tabelle_Patienten.TreKey, dbo.Tabelle_Patienten.Grafik, dbo.Tabelle_Patienten.GuiID, 
                        dbo.Tabelle_Patienten.Objekt, dbo.Tabelle_Patienten.IDP, dbo.Tabelle_Patienten.Mandant, dbo.Tabelle_Patienten.VIP, dbo.Tabelle_Patienten.Titel, 
                        dbo.Tabelle_Patienten.Land, dbo.Tabelle_Patienten.Behindert, dbo.Tabelle_Patienten.Passiv, dbo.Tabelle_Patienten.AdrGruppe, 
                        SUM(dbo.Tabelle_Abre.Betrag) AS Betrag, SUM(dbo.Tabelle_Abre.GesBetrag) AS GesBetrag, MAX(dbo.Tabelle_Abre.Datum) AS Sorter
FROM          dbo.Tabelle_Patienten INNER JOIN
                        dbo.Tabelle_Abre ON dbo.Tabelle_Patienten.ID0 = dbo.Tabelle_Abre.ID0
WHERE      (dbo.Tabelle_Abre.ID1 = @IdTyp) AND (dbo.Tabelle_Abre.Gedruckt = 1) AND (dbo.Tabelle_Abre.Datum >= @IdSta) AND 
                        (dbo.Tabelle_Abre.Datum <= @IdEnd)
GROUP BY dbo.Tabelle_Patienten.ID0, dbo.Tabelle_Patienten.ID3, dbo.Tabelle_Patienten.IDKurz, dbo.Tabelle_Patienten.Geboren, dbo.Tabelle_Patienten.Name, 
                        dbo.Tabelle_Patienten.Vorname, dbo.Tabelle_Patienten.Straße, dbo.Tabelle_Patienten.PLZ, dbo.Tabelle_Patienten.Ort, dbo.Tabelle_Patienten.Firma1, 
                        dbo.Tabelle_Patienten.Telefon1, dbo.Tabelle_Patienten.Telefon2, dbo.Tabelle_Patienten.Telefon3, dbo.Tabelle_Patienten.Telefon4, 
                        dbo.Tabelle_Patienten.Telefon5, dbo.Tabelle_Patienten.Geschlecht, dbo.Tabelle_Patienten.Datum, dbo.Tabelle_Patienten.Briefanrede, 
                        dbo.Tabelle_Patienten.Anschrift, dbo.Tabelle_Patienten.TreKey, dbo.Tabelle_Patienten.Grafik, dbo.Tabelle_Patienten.GuiID, 
                        dbo.Tabelle_Patienten.Objekt, dbo.Tabelle_Patienten.IDP, dbo.Tabelle_Patienten.Mandant, dbo.Tabelle_Patienten.Titel, dbo.Tabelle_Patienten.Land, 
                        dbo.Tabelle_Patienten.Behindert, dbo.Tabelle_Patienten.AdrGruppe, dbo.Tabelle_Patienten.VIP, dbo.Tabelle_Patienten.Passiv
ORDER BY MAX(dbo.Tabelle_Abre.Datum)
GO


SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON
GO


CREATE VIEW dbo.qryPrBuJo4a
AS
SELECT dbo.Tabelle_JourBuch.IDT, dbo.Tabelle_JourBank.IDKurz AS Gegenkonto, dbo.Tabelle_JourBuch.IDK AS Konto, 
                        dbo.Tabelle_JourBuch.IDG, dbo.Tabelle_JourBuch.Datum, dbo.Tabelle_JourBuch.ID0 AS Nr, dbo.Tabelle_JourBuch.IDKurz AS Kontenbezeichnung, 
                        dbo.Tabelle_JourBuch.Einnahme, dbo.Tabelle_JourBuch.Ausgabe, dbo.Tabelle_AbreWr.IDW AS W, dbo.Tabelle_JourBuch.RechNr, 
                        dbo.Tabelle_JourBuch.IDR, dbo.Tabelle_JourBuch.Beleg, 
                        CASE WHEN dbo.Tabelle_JourBuch.IDP > 0 THEN dbo.Tabelle_JourBuch.Buchtext + N' ' + dbo.Tabelle_Patienten.IDKurz WHEN dbo.Tabelle_JourBuch.IDP
                         = 0 OR
                        dbo.Tabelle_JourBuch.IDP IS NULL THEN dbo.Tabelle_JourBuch.Buchtext END AS Buchtext, dbo.Tabelle_JourArt.IDKurz AS Buchungsart, 
                        dbo.Tabelle_JourBuch.Steuer, dbo.Tabelle_JourBuch.Privat, dbo.Tabelle_JourBuch.Abziehbar, dbo.Tabelle_JourBuch.Ermittlung, 
                        dbo.Tabelle_JourBuch.IDP AS PatNr, dbo.Tabelle_JourBuch.Kommentar, dbo.Tabelle_JourBuch.Berichtdatum, dbo.Tabelle_JourBuch.IDB, 
                        dbo.Tabelle_AbreWr.Symbol, 0 AS Saldo, MONTH(dbo.Tabelle_JourBuch.Datum) AS Monat, DATEPART(wk, dbo.Tabelle_JourBuch.Datum) AS Woche, 
                        dbo.Tabelle_JourBuch.Datei
FROM          dbo.Tabelle_JourBuch LEFT OUTER JOIN
                        dbo.Tabelle_Patienten ON dbo.Tabelle_JourBuch.IDP = dbo.Tabelle_Patienten.ID0 LEFT OUTER JOIN
                        dbo.Tabelle_AbreWr ON dbo.Tabelle_JourBuch.Währung = dbo.Tabelle_AbreWr.IDW LEFT OUTER JOIN
                        dbo.Tabelle_JourBank ON dbo.Tabelle_JourBuch.IDB = dbo.Tabelle_JourBank.IDB LEFT OUTER JOIN
                        dbo.Tabelle_JourArt ON dbo.Tabelle_JourBuch.IDA = dbo.Tabelle_JourArt.IDA
WHERE      (dbo.Tabelle_JourBuch.Anfang = 0) AND (dbo.Tabelle_JourBuch.Datum IS NOT NULL) AND (dbo.Tabelle_JourBuch.Serie = 0) AND 
                        (dbo.Tabelle_JourBuch.Vorlage = 0) AND (dbo.Tabelle_JourBuch.Storniert = 0)
GO


