                        dbo.Tabelle_Lab_Beri.Abrechnungstyp, dbo.Tabelle_Lab_Beri.Befundart, dbo.Tabelle_Lab_Beri.[Versichertenart MFR] AS Versichert, 
                        dbo.Tabelle_Lab_Beri.Patienteninformation, dbo.Tabelle_Lab_Beri.Kommentar, dbo.Tabelle_Lab_Beri.Infektiös, 
