                        dbo.Tabelle_Patienten.Briefanrede, dbo.Tabelle_Patienten.Anschrift, dbo.Tabelle_Patienten.TreKey, dbo.Tabelle_Patienten.Grafik, 
                        dbo.Tabelle_Patienten.GuiID, dbo.Tabelle_Patienten.Objekt, dbo.Tabelle_Patienten.IDP, dbo.Tabelle_Patienten.Mandant, dbo.Tabelle_Patienten.VIP, 
                        dbo.Tabelle_Patienten.Titel, dbo.Tabelle_Patienten.Land, dbo.Tabelle_Patienten.Behindert, dbo.Tabelle_Patienten.Passiv, 
                        dbo.Tabelle_Patienten.AdrGruppe, dbo.Tabelle_Patienten.Mailing, SUM(dbo.Tabelle_Abre.Betrag) AS Betrag, SUM(dbo.Tabelle_Abre.GesBetrag) 
                        AS GesBetrag, MAX(dbo.Tabelle_Abre.Datum) AS Sorter
