                        dbo.Tabelle_AbreRe.IDP, dbo.Tabelle_AbreRe.Steuer, CONVERT(CHAR(10), dbo.Tabelle_Abre.Datum, 104) AS Datum, dbo.Tabelle_Abre.GONr AS Ziffer, 
