SELECT      COUNT(ID0) AS Anzahl, CAST(Datum AS DATE) AS Datum, MONTH(Datum) AS Monat, DATEPART(ww, Datum) AS Woche
FROM          dbo.Tabelle_Patienten
WHERE      (MONTH(Datum) = @IdMon) AND (YEAR(Datum) = @IdJah) AND (Passiv = 0) AND (Mitarbeiter = 0) AND (VIP = 0) AND (Arzt = 0)
GROUP BY CAST(Datum AS DATE), MONTH(Datum), DATEPART(ww, Datum)
ORDER BY CAST(Datum AS DATE)
GO


