                        dbo.Tabelle_Abre.Datum, 112) AS Sortierung, CAST(dbo.Tabelle_Abre.ID1 AS CHAR(1)) + CONVERT(CHAR(8), dbo.Tabelle_Abre.Datum, 112) 
                        AS Gruppierung, dbo.Tabelle_Abre.ID3 AS Position, dbo.Tabelle_Abre.RechNr AS Taxe, dbo.Tabelle_Abre.ID1 AS Typ, dbo.Tabelle_Abre.GONr AS Ziffer,
                         dbo.Tabelle_Abre.IDKurz AS Bezeichnung, dbo.Tabelle_Abre.Kommentar, dbo.Tabelle_Abre.Betrag AS Einzelbetrag, 
                        dbo.Tabelle_Abre.GesBetrag AS Gesamtbetrag, dbo.Tabelle_Abre.WVBetrag AS Anzahlungsbetrag, dbo.Tabelle_Abre.LaBetrag AS Einstandspreis, 
                        dbo.Tabelle_Abre.x AS Anzahl, dbo.Tabelle_Abre.Multi, dbo.Tabelle_Abre.Einheit, dbo.Tabelle_Abre.Rabatt AS Einzelrabatt, dbo.Tabelle_Abre.Punkt, 
                        dbo.Tabelle_Abre.Provision, dbo.Tabelle_Abre.Steuer AS Steuersatz, dbo.Tabelle_Abre.IDR AS ReNr, dbo.Tabelle_Abre.Zeit, 
                        dbo.Tabelle_AbreWr.Symbol AS Währung, dbo.Tabelle_AbreDia.GOID AS ICD, dbo.Tabelle_AbreDia.IDKurz AS Diagnose, 
                        dbo.Tabelle_Abre.Druckdatum, dbo.Tabelle_Abre.Analog, dbo.Tabelle_Abre.IDM, dbo.Tabelle_Patienten.IDKurz AS Mitarbeiter
