CREATE VIEW dbo.qryPrSimTaPa3
AS
SELECT      TOP 1 dbo.Tabelle_Patienten.IDKurz AS Patient, CAST(CONVERT(CHAR(10), dbo.Tabelle_Abre.Datum, 104) AS DATE) AS Datum, 
                        dbo.Tabelle_Abre.ID1 AS Typ, COUNT(dbo.Tabelle_Abre.ID2) AS Anzahl, SUM(dbo.Tabelle_Abre.GesBetrag) AS Gesamt, SUM(dbo.Tabelle_Abre.Zeit) 
                        AS Zeit, dbo.Tabelle_AbreWr.Symbol, dbo.Tabelle_Patienten.IDP AS IDT, CONVERT(CHAR(8), dbo.Tabelle_Abre.Datum, 112) AS Sorter
FROM          dbo.Tabelle_AbreWr INNER JOIN
                        dbo.Tabelle_AbreRe INNER JOIN
                        dbo.Tabelle_Patienten ON dbo.Tabelle_AbreRe.ID0 = dbo.Tabelle_Patienten.ID0 INNER JOIN
                        dbo.Tabelle_Abre ON dbo.Tabelle_AbreRe.ID1 = dbo.Tabelle_Abre.IDR ON dbo.Tabelle_AbreWr.IDW = dbo.Tabelle_AbreRe.Währung
WHERE      (dbo.Tabelle_AbreRe.Storniert = 0) AND (dbo.Tabelle_AbreRe.Type LIKE N'R' OR
                        dbo.Tabelle_AbreRe.Type LIKE N'A' OR
                        dbo.Tabelle_AbreRe.Type LIKE N'L' OR
                        dbo.Tabelle_AbreRe.Type LIKE N'G' OR
                        dbo.Tabelle_AbreRe.Type LIKE N'I') AND (dbo.Tabelle_Abre.Storniert = 0)
GROUP BY CAST(CONVERT(CHAR(10), dbo.Tabelle_Abre.Datum, 104) AS DATE), dbo.Tabelle_Patienten.IDKurz, dbo.Tabelle_AbreWr.Symbol, 
                        dbo.Tabelle_Abre.ID1, dbo.Tabelle_Patienten.IDP, CONVERT(CHAR(8), dbo.Tabelle_Abre.Datum, 112)
HAVING       (dbo.Tabelle_Abre.ID1 < 10)
ORDER BY dbo.Tabelle_Patienten.IDKurz, CONVERT(CHAR(8), dbo.Tabelle_Abre.Datum, 112), dbo.Tabelle_Abre.ID1
GO


