                        dbo.Tabelle_AbreRe.Diagnose, dbo.Tabelle_AbreRe.Steuer, dbo.Tabelle_AbreRe.Type, dbo.Tabelle_AbreRe.IDP, CONVERT(CHAR(10), 
                        dbo.Tabelle_Abre.Datum, 104) AS Datum, dbo.Tabelle_Abre.GONr AS Ziffer, dbo.Tabelle_Abre.IDKurz AS Leistung, dbo.Tabelle_Abre.x AS Anzahl, 
                        dbo.Tabelle_Abre.Multi, dbo.Tabelle_Abre.Einheit, dbo.Tabelle_Abre.Betrag AS Einzelbetrag, dbo.Tabelle_Abre.GesBetrag AS Gesamtbetrag, 
