                      dbo.Tabelle_PatientenLab.IDU, MAX(dbo.Tabelle_Lab_Typ.IDKurz) AS Zuweisung, SUM(dbo.Tabelle_AbreBes.Betrag) AS EK, 
                      SUM(dbo.Tabelle_AbreBes.GesBetrag) AS VK, dbo.Tabelle_AbreWr.Symbol AS W
FROM         dbo.Tabelle_Lab_Typ INNER JOIN
                      dbo.Tabelle_AbreBes ON dbo.Tabelle_Lab_Typ.IDU = dbo.Tabelle_AbreBes.IDU INNER JOIN
                      dbo.Tabelle_AbreWr ON dbo.Tabelle_AbreBes.Währung = dbo.Tabelle_AbreWr.IDW INNER JOIN
                      dbo.Tabelle_Patienten INNER JOIN
                      dbo.Tabelle_PatientenLab ON dbo.Tabelle_Patienten.ID0 = dbo.Tabelle_PatientenLab.ID0 INNER JOIN
                      dbo.Tabelle_Lab_Beri ON dbo.Tabelle_PatientenLab.IDA = dbo.Tabelle_Lab_Beri.[Anforderungs-Ident] ON 
                      dbo.Tabelle_AbreBes.IDA = dbo.Tabelle_PatientenLab.ID1
WHERE     (dbo.Tabelle_Lab_Beri.Fertig = 0)
GROUP BY dbo.Tabelle_PatientenLab.IDA, dbo.Tabelle_Lab_Beri.[Auftragsnummer Labor], dbo.Tabelle_PatientenLab.Datum, dbo.Tabelle_Patienten.IDKurz, 
                      dbo.Tabelle_PatientenLab.Name, dbo.Tabelle_PatientenLab.Geschlecht, dbo.Tabelle_PatientenLab.Geboren, dbo.Tabelle_PatientenLab.Typ, 
                      dbo.Tabelle_PatientenLab.IDU, dbo.Tabelle_AbreWr.Symbol, CAST(dbo.Tabelle_PatientenLab.Befundung AS char(4))
GO


