CREATE PROCEDURE dbo.qryTerNam3
    @IdStr nvarchar(250),
    @IdJah int
AS
SELECT      MIN(ID0) AS ID0, MIN(ID2) AS ID2, MIN(IDR) AS IDR, MIN(IDSer) AS IDSer, MIN(IDKurz) AS IDKurz, MIN(VonDat) AS VonDat, MIN(BisDat) AS BisDat, 
                        MIN(ZeiVon) AS ZeiVon, MIN(ZeiBis) AS ZeiBis, MIN(ZeiVor) AS ZeiVor, MIN(Priorität) AS Priorität, MIN(Vorwarn) AS Vorwarn, MIN(Farbe) AS Farbe, 
                        MIN(Anzahl) AS Anzahl, MIN(Patient) AS Patient, MIN(Datei) AS Datei, MIN(Datum) AS Datum, MIN(Farbtyp) AS Farbtyp, MIN(IDP) AS IDP, MIN(IDM) 
                        AS IDM, MIN(Behandler) AS Behandler, MIN(Raum) AS Raum, MIN(GuiID) AS GuiID, MasTer AS MasTer, MIN(GesBetrag) AS GesBetrag, MIN(SerBetrag) 
                        AS SerBetrag, MIN(BezBetrag) AS BezBetrag, MIN(BezBetrag2) AS BezBetrag2, MIN(BezBetrag2) AS BezBetrag2, MIN(SerTyp) AS SerTyp, 
                        MIN(TerTyp) AS TerTyp, MIN(Fallig1) AS Fallig1, MIN(Fallig2) AS Fallig2, MIN(DATEPART(dw, VonDat)) AS Wochentag
FROM          dbo.Tabelle_PatientenWv
WHERE      (Patient LIKE @IdStr) AND (YEAR(VonDat) = @IdJah) AND (Passiv = 0)
GROUP BY MasTer
ORDER BY MIN(VonDat) DESC, MIN(ZeiVon) DESC
GO


