CREATE PROCEDURE dbo.qryPrIdk
    @pExchangeUid nvarchar(200),
    @pVonDat datetime,
    @pBisDat datetime,
    @pZeiVon datetime,
    @pZeiBis datetime
AS
BEGIN
	select count(*) from tabelle_patientenwv
	where ExUID is null
	and not ((CAST(CAST(vondat AS DATE) AS DATETIME) + cast(CAST(zeivon AS TIME) as datetime)) >= (CAST(CAST(@pBisDat AS DATE) AS DATETIME) + cast(CAST(@pZeiBis AS TIME) as datetime)) or 
	(CAST(CAST(bisdat AS DATE) AS DATETIME) + cast(CAST(zeibis AS TIME) as datetime)) <= (CAST(CAST(@pVonDat AS DATE) AS DATETIME) + cast(CAST(@pZeiVon AS TIME) as datetime)))
	and passiv <> 1
END
GO


