                        AS IDM, MIN(Behandler) AS Behandler, MIN(Raum) AS Raum, MIN(GuiID) AS GuiID, MasTer, MIN(GesBetrag) AS GesBetrag, MIN(SerBetrag) 
                        AS SerBetrag, MIN(BezBetrag) AS BezBetrag, MIN(BezBetrag2) AS BezBetrag2, MIN(SerTyp) AS SerTyp, MIN(TerTyp) AS TerTyp, MIN(Fallig1) 
