CREATE PROCEDURE dbo.qryTerAdd
    @ExchangeUid nvarchar(200) = null,
    @GuiID nvarchar(100) = null,
    @IDKurz nvarchar(250) = null,
    @Patient nvarchar(250) = null,
    @VonDat datetime = null,
    @BisDat datetime = null,
    @ZeiVon datetime = null,
    @ZeiBis datetime = null,
    @Priorität int = null,
    @Datei nvarchar(250) = null,
    @Datum datetime = null,
    @LastModification datetime = null,
    @Raum nvarchar(255) = null,
    @Erinnerung bit = null,
    @Selekt bit = null,
    @ParentID nvarchar(200) = null,
    @ID0 int,
    @IDR int,
    @IDP int,
    @IDM int,
    @Farbtyp smallint,
    @Passiv bit,
    @Vorwarn smallint,
    @Anzahl smallint,
    @SerTyp int,
    @Wiederholung bit,
    @Aufgabe bit,
    @Erledigt bit,
    @Drucken bit,
    @Vorlage bit,
    @Ausgangstermin bit,
    @Geschlecht smallint,
    @Abhaken bit,
    @OnlTer bit,
    @OnlGes bit
AS
INSERT INTO Tabelle_PatientenWv (
			ExUID,
			GuiID,
			IDKurz,
			Patient,
			VonDat,
			BisDat,
			ZeiVon,
			ZeiBis,
			Priorität,
			Datei,
			Datum,
			LastModification,
			Raum,
			Erinnerung,
			Selekt,
			ParentID,
			IDP,
			IDM,
			Replicated,
			ID0,
			IDR,
			Farbtyp,
			Passiv,
			Vorwarn,
			Anzahl,
			SerTyp,
			Wiederholung,	
			Aufgabe,
			Erledigt,
			Drucken,
			Vorlage,
			Ausgangstermin,
			Geschlecht,
			Abhaken,
			OnlTer,
			OnlGes
		)
		VALUES(
			@ExchangeUid,
			@GuiID,
			@IDKurz,
			@Patient,
			@VonDat,
			@BisDat,
			@ZeiVon,
			@ZeiBis,
			@Priorität,
			@Datei,
			@Datum,
			@LastModification,
			@Raum,
			@Erinnerung,
			@Selekt,
			@ParentID,
			@IDP,
			@IDM,
			0,
			@ID0,
			@IDR,
			@Farbtyp,
			@Passiv,
			@Vorwarn,
			@Anzahl,
			@SerTyp,
			@Wiederholung,	
			@Aufgabe,
			@Erledigt,
			@Drucken,
			@Vorlage,
			@Ausgangstermin,
			@Geschlecht,
			@Abhaken,
			@OnlTer,
			@OnlGes
		);
 SELECT SCOPE_IDENTITY();
GO


