                        MIN(Anzahl) AS Anzahl, MIN(Patient) AS Patient, MIN(Datei) AS Datei, MIN(Datum) AS Datum, MIN(Farbtyp) AS Farbtyp, MIN(IDP) AS IDP, MIN(IDM) 
                        AS IDM, MIN(Behandler) AS Behandler, MIN(Raum) AS Raum, MIN(GuiID) AS GuiID, MIN(MasTer) AS MasTer, MIN(GesBetrag) AS GesBetrag, 
                        MIN(SerBetrag) AS SerBetrag, MIN(BezBetrag) AS BezBetrag, MIN(BezBetrag2) AS BezBetrag2, MIN(BezBetrag2) AS BezBetrag2, MIN(SerTyp) 
