CREATE VIEW dbo.qrySimRzEx
AS
SELECT dbo.Tabelle_Patienten.ID0, dbo.Tabelle_Patienten.IDKurz AS Patient, dbo.Tabelle_Patienten.Anrede, dbo.Tabelle_Patienten.Titel, 
                        dbo.Tabelle_Patienten.Name, dbo.Tabelle_Patienten.Vorname, dbo.Tabelle_Patienten.Straße, dbo.Tabelle_Patienten.PLZ, dbo.Tabelle_Patienten.Ort, 
                        dbo.Tabelle_Patienten.Geschlecht, dbo.Tabelle_Patienten.Geboren, dbo.Tabelle_Patienten.IDP, dbo.Tabelle_Patienten.Diagnose AS Diagnosetext, 
                        dbo.Tabelle_RezeptP.Datum AS Rezeptdatum, dbo.Tabelle_RezeptP.Rezepttext, dbo.Tabelle_AbreDia.GOID AS PZN, 
                        dbo.Tabelle_AbreDia.IDKurz AS Medikament, Tabelle_AbreDia_1.GOID AS ICD, Tabelle_AbreDia_1.IDKurz AS Diagnose, 
                        dbo.Tabelle_RezeptP.IDM
FROM          dbo.Tabelle_Patienten INNER JOIN
                        dbo.Tabelle_RezeptP ON dbo.Tabelle_Patienten.ID0 = dbo.Tabelle_RezeptP.ID0 LEFT OUTER JOIN
                        dbo.Tabelle_AbreDia ON dbo.Tabelle_RezeptP.ID1 = dbo.Tabelle_AbreDia.IDR LEFT OUTER JOIN
                        dbo.Tabelle_AbreDia Tabelle_AbreDia_1 ON dbo.Tabelle_AbreDia.IDD = Tabelle_AbreDia_1.IDD
WHERE      (dbo.Tabelle_AbreDia.Selekt = 1)
GO


