                        dbo.Tabelle_AbreRe.Berichtdatum, dbo.Tabelle_AbreRe.Kopie, dbo.Tabelle_AbreRe.Steuer, dbo.Tabelle_AbreRe.IDT, dbo.Tabelle_AbreRe.Storniert, 
