                        dbo.Tabelle_AbreRe.RzTex, dbo.Tabelle_AbreRe.Grund, dbo.Tabelle_AbreRe.Versand, dbo.Tabelle_AbreRe.IDF, dbo.Tabelle_Formulare.IdTit
FROM          dbo.Tabelle_AbreRe INNER JOIN
                        dbo.qrySimReDia ON dbo.Tabelle_AbreRe.ID1 = dbo.qrySimReDia.IDR LEFT OUTER JOIN
                        dbo.Tabelle_Formulare ON dbo.Tabelle_AbreRe.IDF = dbo.Tabelle_Formulare.ID1 LEFT OUTER JOIN
                        dbo.Tabelle_Patienten ON dbo.Tabelle_AbreRe.ID0 = dbo.Tabelle_Patienten.ID0 LEFT OUTER JOIN
                        dbo.Tabelle_PatientenG2 ON dbo.Tabelle_AbreRe.ID3 = dbo.Tabelle_PatientenG2.ID3 LEFT OUTER JOIN
                        dbo.Tabelle_AbreWr ON dbo.Tabelle_AbreRe.Währung = dbo.Tabelle_AbreWr.IDW LEFT OUTER JOIN
                        dbo.Tabelle_AbreOPZ ON dbo.Tabelle_AbreRe.IDZ = dbo.Tabelle_AbreOPZ.IDZ
WHERE      (dbo.qrySimReDia.IDKurz LIKE @IdStr) AND (dbo.Tabelle_AbreRe.Type LIKE N'R' OR
                        dbo.Tabelle_AbreRe.Type LIKE N'L' OR
                        dbo.Tabelle_AbreRe.Type LIKE N'A' OR
                        dbo.Tabelle_AbreRe.Type LIKE N'G' OR
                        dbo.Tabelle_AbreRe.Type LIKE N'I')
ORDER BY dbo.Tabelle_AbreRe.ID1 DESC
GO


