CREATE VIEW dbo.qryPrBuKom2
AS
SELECT CAST(YEAR(Datum) AS char(4)) AS Jahr, RIGHT('00' + CAST(MONTH(Datum) AS VARCHAR(2)), 2) AS Sort, 
                        RIGHT('00' + CAST(MONTH(Datum) AS VARCHAR(2)), 2) + '/' + CAST(YEAR(Datum) AS char(4)) AS Gruppe, CAST(MONTH(Datum) AS char(2)) AS Monat, 
                        IDK AS Kontonummer, SUM(Einn - Ausg) AS Gesamtsumme, IDT
FROM          dbo.qrySimBuGes
GROUP BY CAST(YEAR(Datum) AS char(4)), CAST(MONTH(Datum) AS char(2)), RIGHT('00' + CAST(MONTH(Datum) AS VARCHAR(2)), 2) + '/' + CAST(YEAR(Datum) 
                        AS char(4)), IDK, RIGHT('00' + CAST(MONTH(Datum) AS VARCHAR(2)), 2), IDT
HAVING       (CAST(YEAR(Datum) AS char(4)) IS NOT NULL)
GO


SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER OFF
GO


