SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE dbo.qryTerNotRet
    @IdSta smallint,
    @IdDat datetime
AS
SELECT      dbo.Tabelle_PatientenWv.ID2, dbo.Tabelle_PatientenWv.GuiID, dbo.Tabelle_PatientenWv.IDKurz AS Ter_Betreff, 
                        dbo.Tabelle_PatientenWv.VonDat AS Ter_DatSta, dbo.Tabelle_PatientenWv.BisDat AS Ter_DatEnd, dbo.Tabelle_PatientenWv.ZeiVon AS Ter_ZeiVon, 
                        dbo.Tabelle_PatientenWv.ZeiBis AS Ter_ZeiBis, dbo.Tabelle_PatientenWv.Datum AS Ter_Erstellt, dbo.Tabelle_KontOrt.Ort AS Ter_Raum, 
                        dbo.Tabelle_PatientenWv.IDM AS Mit_Nummer, Tabelle_Patienten_1.IDKurz AS Mit_Kennung, Tabelle_Patienten_1.Firma2 AS Mit_Anzeigename, 
                        Tabelle_Patienten_1.Anrede AS Mit_Anrede, Tabelle_Patienten_1.Titel AS Mit_Titel, Tabelle_Patienten_1.Name AS Mit_Name, 
                        Tabelle_Patienten_1.Vorname AS Mit_Vorname, Tabelle_Patienten_1.Objekt AS Mit_Signatur, dbo.Tabelle_PatientenWv.ID0 AS Pat_Nummer, 
                        dbo.Tabelle_Patienten.IDKurz AS Pat_Kennung, dbo.Tabelle_Patienten.Anrede AS Pat_Anrede, dbo.Tabelle_Patienten.Titel AS Pat_Titel, 
                        dbo.Tabelle_Patienten.Name AS Pat_Name, dbo.Tabelle_Patienten.Vorname AS Pat_Vorname, dbo.Tabelle_Patienten.Briefanrede AS Pat_Briefanrede, 
                        dbo.Tabelle_PatientenWv.Telefon5 AS Pat_Email1, dbo.Tabelle_Patienten.Telefon5 AS Pat_Email2, dbo.Tabelle_Patienten.Telefon6 AS Pat_Email3, 
                        dbo.Tabelle_Patienten.Telefon4 AS Pat_Telefon1, dbo.Tabelle_Patienten.Telefon1 AS Pat_Telefon2, dbo.Tabelle_Patienten.Geboren AS Pat_Geboren, 
                        dbo.qryTerNotMail.Mit_SMTP_Server, dbo.qryTerNotMail.Mit_SMTP_Emailadresse, dbo.qryTerNotMail.Mit_SMTP_SenderName, 
                        dbo.qryTerNotMail.Mit_SMTP_Antwortadresse, dbo.qryTerNotMail.Mit_SMTP_Username, dbo.qryTerNotMail.Mit_SMTP_Passwort, 
                        dbo.qryTerNotMail.Mit_SMTP_Port, dbo.qryTerNotMail.Mit_SMTP_TSLTyp, dbo.qryTerNotMail.Mit_SMTP_Autent, 
                        dbo.Tabelle_PatientenWv.NotifyStatus, dbo.Tabelle_PatientenWv.NotifySetDate, dbo.Tabelle_PatientenWv.NotifySetTime, 
                        dbo.Tabelle_PatientenWv.NotifyValue
FROM          dbo.qryTerNotMail INNER JOIN
                        dbo.Tabelle_Patienten Tabelle_Patienten_1 ON dbo.qryTerNotMail.Mit_Nummer = Tabelle_Patienten_1.ID0 INNER JOIN
                        dbo.Tabelle_PatientenWv ON Tabelle_Patienten_1.ID0 = dbo.Tabelle_PatientenWv.IDM LEFT OUTER JOIN
                        dbo.Tabelle_Patienten ON dbo.Tabelle_PatientenWv.ID0 = dbo.Tabelle_Patienten.ID0 LEFT OUTER JOIN
                        dbo.Tabelle_KontOrt ON dbo.Tabelle_PatientenWv.IDR = dbo.Tabelle_KontOrt.ID4
WHERE      (dbo.Tabelle_PatientenWv.NotifyStatus > @IdSta) AND (dbo.Tabelle_PatientenWv.Vorlage = 0) AND (dbo.Tabelle_PatientenWv.Passiv = 0) AND 
                        (CAST(dbo.Tabelle_PatientenWv.NotifySetDate AS DATE) <= CAST(@IdDat AS DATE)) AND (CAST(dbo.Tabelle_PatientenWv.VonDat AS DATE) 
                        >= CAST(@IdDat AS DATE))
ORDER BY dbo.Tabelle_PatientenWv.VonDat
GO


